@startuml
package Actor {
    actor "I Vehiculo" as vehiculo
}

package Interface {
    interface I {
        marca: string
        modelo: string
        velocidadMax: number

        encender(): void
        apagar(): void
        acelerar(): void
        frenar(): void
    }
}

package Database {
    database DB {
        vehiculo
    }
}

package Class {
    class Recargable {
        interface I {
            autonomia: string
            cargar(number): void
            descargar(number): void
        }
    }

    class BiciElectrica {
        interface C {
            pedalear(): void
        }
    }

    class AutoElectrico {
        interface C {
            manejoAutonomo(): void
        }
    }

    class MonopatinElectrico {
        interface C {
            ajustarAltura(): void
            plegar(): void
        }
    }
}

package Class {
    class VehiculoRecargable {
        interface I {
            marca: string
            modelo: string
            velocidadMax: number

            encender(): void
            apagar(): void
            acelerar(): void
            frenar(): void
        }
    }
}

class Vehiculo extends VehiculoRecargable {
    interface I {
        marca: string
        modelo: string
        velocidadMax: number

        encender(): void
        apagar(): void
        acelerar(): void
        frenar(): void
    }
}

class Recargable extends VehiculoRecargable {
    interface I {
        autonomia: string
        cargar(number): void
        descargar(number): void
    }
}

class BiciElectrica extends Recargable {
    interface C {
        pedalear(): void
    }
}

class AutoElectrico extends Recargable {
    interface C {
        manejoAutonomo(): void
    }
}

class MonopatinElectrico extends Recargable {
    interface C {
        ajustarAltura(): void
        plegar(): void
    }
}

@enduml
